import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../App.css';

const api = axios.create({
  baseURL: 'http://localhost:5000',
  // withCredentials: true,
});

function Login() {
  const [form, setForm] = useState({ login: '', password: '' });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const response = await api.post('/login', {
        login: form.login,
        password: form.password
      });

      if (response.status === 200) {
        // Успешный вход - переходим на dashboard
        navigate('/');
      }
    } catch (err) {
      if (err.response) {
        setError(err.response.data.message || 'Ошибка входа');
      } else if (err.request) {
        setError('Нет ответа от сервера. Проверьте, запущен ли Flask.');
      } else {
        setError('Ошибка при отправке запроса');
      }
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setForm(prev => ({
      ...prev,
      [name]: value
    }));
    // Очищаем ошибку при вводе
    if (error) setError('');
  };

  return (
    <div className="app-container">
      <div className="app-card">
        <h2 className="app-title">Вход в систему</h2>
        <p className="app-subtitle">Введите логин и пароль</p>

        {message && (
          <div className={`message ${messageType}-message`}>
            {message}
          </div>
        )}

        <form onSubmit={handleLogin} className="app-form">
          <div className="form-group">
            <input
              type="text"
              name="login"
              value={form.login}
              onChange={handleInputChange}
              className="form-input"
              placeholder="Логин"
              required
              disabled={loading}
              autoComplete="username"
            />
          </div>

          <div className="form-group">
            <input
              type="password"
              name="password"
              value={form.password}
              onChange={handleInputChange}
              className="form-input"
              placeholder="Пароль"
              required
              disabled={loading}
              autoComplete="current-password"
            />
          </div>

          <button 
            type="submit" 
            className="login-button"
            disabled={loading || !form.login || !form.password}
          >
            {loading ? (
              <>
                <span className="spinner"></span>
                Вход...
              </>
            ) : 'Войти'}
          </button>
        </form>

        <div className="info-box">
          <p><strong>Как это работает:</strong></p>
          <ul>
            <li>Flask-Login создает сессию на сервере</li>
            <li>Браузер получает куку session</li>
            <li>Все последующие запросы отправляют эту куку автоматически</li>
            <li>Для выхода сессия удаляется на сервере</li>
          </ul>
          <p style={{ marginTop: '10px', fontSize: '13px' }}>
            <strong>Тестовые данные:</strong> admin / admin123 (или ваши данные из БД)
          </p>
        </div>
      </div>
    </div>
  );
}

export default Login;
